const allItems = $input.all();

let deals = [];
let contacts = [];
let owners = [];
let pipeline = null;
let closedDeals = [];
let lastWeekRows = [];

allItems.forEach(item => {
  const data = item.json;
  if (!data || data.skipped) return;

  // Detect pipeline — has stages array
  if (data.results?.[0]?.stages !== undefined) {
    pipeline = data.results[0];
    return;
  }

  // Detect owners — results with firstName
  if (data.results?.[0]?.firstName !== undefined) {
    owners = data.results;
    return;
  }

  // Detect deals vs closed deals
  if (data.results?.[0]?.properties?.dealname !== undefined) {
    const hasClosedDeals = data.results.some(d =>
      d.properties.dealstage === 'closedwon' ||
      d.properties.dealstage === 'closedlost'
    );

    const hasOpenDeals = data.results.some(d =>
      d.properties.dealstage !== 'closedwon' &&
      d.properties.dealstage !== 'closedlost'
    );

    if (hasClosedDeals && !hasOpenDeals) {
      closedDeals = data.results;
    } else {
      deals = data.results;
    }

    return;
  }

  // Detect contacts
  if (data.results?.[0]?.properties?.firstname !== undefined) {
    contacts = data.results;
    return;
  }

  // Detect audit log rows
  if (data.week !== undefined || data.total_pipeline_value !== undefined) {
    lastWeekRows.push(item);
    return;
  }
});

// ---------- HELPERS ----------

function safeDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

function daysBetween(laterDate, earlierDate) {
  if (!earlierDate) return 0;
  return Math.floor((laterDate - earlierDate) / (1000 * 60 * 60 * 24));
}

function money(value) {
  return parseFloat(value) || 0;
}

// ---------- OWNER LOOKUP ----------

const ownerMap = {};
owners.forEach(o => {
  ownerMap[o.id] = `${o.firstName || ''} ${o.lastName || ''}`.trim() || 'Unassigned';
});

// ---------- PIPELINE / STAGE METADATA ----------

const closedStages = new Set();
const stageMetadata = {};

if (pipeline) {
  pipeline.stages.forEach(s => {
    stageMetadata[s.id] = {
      label: s.label,
      probability: parseFloat(s.metadata?.probability) || 0.2,
      isClosed: s.metadata?.isClosed === 'true'
    };

    if (s.metadata?.isClosed === 'true') {
      closedStages.add(s.id);
    }
  });
}

const now = new Date();

// ---------- RUN MODE CONFIGURATION ----------
// crm_mode comes from the "Set Run Mode" node.
// Use "demo" to force all detection branches to appear immediately.
// Use "production" for realistic operational thresholds.

const modeItem = allItems.find(item => item.json.crm_mode)?.json || {};
const CRM_MODE = modeItem.crm_mode || 'production';

const DEMO_MODE = CRM_MODE === 'demo';

const IDLE_DAYS = DEMO_MODE ? 0 : 14;
const STUCK_DAYS = DEMO_MODE ? 0 : 30;
const UNCONTACTED_DAYS = DEMO_MODE ? 0 : 7;

const MONTHLY_TARGET = 150000;

// ---------- CHECK 1 — IDLE DEALS ----------

const idleDeals = [];

deals.forEach(deal => {
  const props = deal.properties;
  if (closedStages.has(props.dealstage)) return;

  const lastActivity =
    safeDate(props.notes_last_activity) ||
    safeDate(props.hs_lastmodifieddate) ||
    safeDate(props.createdate);

  const daysSince = daysBetween(now, lastActivity);

  if (daysSince >= IDLE_DAYS) {
    idleDeals.push({
      name: props.dealname || 'Unnamed deal',
      owner: ownerMap[props.hubspot_owner_id] || 'Unassigned',
      amount: money(props.amount),
      days_idle: daysSince,
      stage: stageMetadata[props.dealstage]?.label || props.dealstage,
      url: deal.url || ''
    });
  }
});

// ---------- CHECK 2 — OVERDUE CLOSE DATES ----------

const overdueDeals = [];

deals.forEach(deal => {
  const props = deal.properties;
  if (closedStages.has(props.dealstage)) return;
  if (!props.closedate) return;

  const closeDate = safeDate(props.closedate);
  if (!closeDate) return;

  const daysOverdue = daysBetween(now, closeDate);

  if (daysOverdue > 0) {
    overdueDeals.push({
      name: props.dealname || 'Unnamed deal',
      owner: ownerMap[props.hubspot_owner_id] || 'Unassigned',
      amount: money(props.amount),
      close_date: props.closedate.split('T')[0],
      days_overdue: daysOverdue,
      stage: stageMetadata[props.dealstage]?.label || props.dealstage,
      url: deal.url || ''
    });
  }
});

// ---------- CHECK 3 — LEADS WITH NO LOGGED FOLLOW-UP ----------

const uncontactedLeads = [];

contacts.forEach(contact => {
  const props = contact.properties;

  const createdDate = safeDate(props.createdate);
  const daysSinceCreated = daysBetween(now, createdDate);

  if (daysSinceCreated >= UNCONTACTED_DAYS && !props.notes_last_activity) {
    uncontactedLeads.push({
      name: `${props.firstname || ''} ${props.lastname || ''}`.trim() || 'Unnamed contact',
      owner: ownerMap[props.hubspot_owner_id] || 'Unassigned',
      days_since_created: daysSinceCreated,
      email: props.email || 'No email',
      url: contact.url || ''
    });
  }
});

// ---------- CHECK 4 — MISSING CRITICAL DATA ----------

const missingData = {
  contacts_no_reachable_info: [],
  deals_no_close_date: [],
  deals_no_owner: []
};

contacts.forEach(contact => {
  const props = contact.properties;

  if (!props.email && !props.phone && !props.mobilephone) {
    missingData.contacts_no_reachable_info.push({
      name: `${props.firstname || ''} ${props.lastname || ''}`.trim() || 'Unnamed contact',
      owner: ownerMap[props.hubspot_owner_id] || 'Unassigned',
      url: contact.url || ''
    });
  }
});

deals.forEach(deal => {
  const props = deal.properties;
  if (closedStages.has(props.dealstage)) return;

  if (!props.closedate) {
    missingData.deals_no_close_date.push({
      name: props.dealname || 'Unnamed deal',
      owner: ownerMap[props.hubspot_owner_id] || 'Unassigned',
      amount: money(props.amount),
      url: deal.url || ''
    });
  }

  if (!props.hubspot_owner_id || props.hubspot_owner_id === '') {
    missingData.deals_no_owner.push({
      name: props.dealname || 'Unnamed deal',
      amount: money(props.amount),
      url: deal.url || ''
    });
  }
});

// ---------- CHECK 5 — STUCK DEALS ----------

const stuckDeals = [];

deals.forEach(deal => {
  const props = deal.properties;
  if (closedStages.has(props.dealstage)) return;

  const lastStageMovement =
    safeDate(props.hs_lastmodifieddate) ||
    safeDate(props.createdate);

  const daysInStage = daysBetween(now, lastStageMovement);

  if (daysInStage >= STUCK_DAYS) {
    stuckDeals.push({
      name: props.dealname || 'Unnamed deal',
      owner: ownerMap[props.hubspot_owner_id] || 'Unassigned',
      amount: money(props.amount),
      stage: stageMetadata[props.dealstage]?.label || props.dealstage,
      days_in_stage: daysInStage,
      url: deal.url || ''
    });
  }
});

// ---------- FORECAST ----------

const openDeals = deals.filter(d => !closedStages.has(d.properties.dealstage));

const totalPipelineValue = openDeals.reduce(
  (sum, d) => sum + money(d.properties.amount),
  0
);

const weightedPipeline = openDeals.reduce((sum, d) => {
  const probability = stageMetadata[d.properties.dealstage]?.probability || 0.2;
  return sum + money(d.properties.amount) * probability;
}, 0);

const forecastGap = MONTHLY_TARGET - weightedPipeline;

// ---------- WEEK OVER WEEK ----------

let pipelineChangePct = 0;

if (lastWeekRows.length > 0) {
  const lastRow = lastWeekRows[lastWeekRows.length - 1].json;
  const lastWeekPipeline = parseFloat(lastRow.total_pipeline_value) || 0;

  if (lastWeekPipeline > 0) {
    pipelineChangePct = Math.round(
      ((totalPipelineValue - lastWeekPipeline) / lastWeekPipeline) * 100
    );
  }
}

// ---------- AT RISK VALUE ----------

const atRiskValue = [...new Map(
  [...idleDeals, ...overdueDeals].map(d => [d.name, d])
).values()].reduce((sum, d) => sum + (d.amount || 0), 0);

const atRiskPercentage = totalPipelineValue > 0
  ? Math.round((atRiskValue / totalPipelineValue) * 100)
  : 0;

// ---------- DATA QUALITY SCORE ----------

const totalRecordsChecked = openDeals.length + contacts.length;

const dataQualityIssues =
  missingData.contacts_no_reachable_info.length +
  missingData.deals_no_close_date.length +
  missingData.deals_no_owner.length;

const dataQualityScore = totalRecordsChecked > 0
  ? Math.max(0, Math.round(100 - ((dataQualityIssues / totalRecordsChecked) * 100)))
  : 100;

// ---------- FORECAST CONFIDENCE ----------

let forecastConfidence = 'High';

if (
  forecastGap > 0 ||
  (totalPipelineValue > 0 && (atRiskValue / totalPipelineValue) > 0.4)
) {
  forecastConfidence = 'Low';
} else if (
  totalPipelineValue > 0 &&
  (atRiskValue / totalPipelineValue) > 0.2
) {
  forecastConfidence = 'Medium';
}

// ---------- TOP RISK DEALS ----------

const topRiskDeals = [...new Map(
  [...overdueDeals, ...idleDeals, ...stuckDeals].map(d => [d.name, d])
).values()]
  .sort((a, b) => (b.amount || 0) - (a.amount || 0))
  .slice(0, 5);

// ---------- REP PERFORMANCE ----------

const repStats = {};

openDeals.forEach(deal => {
  const owner = ownerMap[deal.properties.hubspot_owner_id] || 'Unassigned';

  if (!repStats[owner]) {
    repStats[owner] = {
      idle: 0,
      overdue: 0,
      uncontacted: 0,
      total_deals: 0
    };
  }

  repStats[owner].total_deals++;
});

idleDeals.forEach(d => {
  if (!repStats[d.owner]) {
    repStats[d.owner] = {
      idle: 0,
      overdue: 0,
      uncontacted: 0,
      total_deals: 0
    };
  }

  repStats[d.owner].idle++;
});

overdueDeals.forEach(d => {
  if (!repStats[d.owner]) {
    repStats[d.owner] = {
      idle: 0,
      overdue: 0,
      uncontacted: 0,
      total_deals: 0
    };
  }

  repStats[d.owner].overdue++;
});

uncontactedLeads.forEach(d => {
  if (!repStats[d.owner]) {
    repStats[d.owner] = {
      idle: 0,
      overdue: 0,
      uncontacted: 0,
      total_deals: 0
    };
  }

  repStats[d.owner].uncontacted++;
});

const repScores = Object.entries(repStats)
  .map(([name, stats]) => {
    const issues = stats.idle + stats.overdue + stats.uncontacted;
    const score = Math.max(0, 10 - (issues * 2));

    return {
      name,
      score,
      follow_up_risk: score <= 4 ? 'High' : score <= 7 ? 'Medium' : 'Low',
      ...stats
    };
  })
  .sort((a, b) => a.score - b.score);

// ---------- WIN / LOSS ----------

const closedWon = closedDeals.filter(d => d.properties.dealstage === 'closedwon');
const closedLost = closedDeals.filter(d => d.properties.dealstage === 'closedlost');

const wonValue = closedWon.reduce(
  (sum, d) => sum + money(d.properties.amount),
  0
);

const lostValue = closedLost.reduce(
  (sum, d) => sum + money(d.properties.amount),
  0
);

const closedDealCount = closedWon.length + closedLost.length;

const winRate = closedDealCount > 0
  ? Math.round((closedWon.length / closedDealCount) * 100)
  : 0;

// ---------- WEEK LABEL ----------

const weekNumber = Math.ceil(
  (Math.floor((now - new Date(now.getFullYear(), 0, 1)) / 86400000) + 1) / 7
);

const weekLabel = `${now.getFullYear()}-W${String(weekNumber).padStart(2, '0')}`;

// ---------- FINAL OUTPUT ----------

return [
  {
    json: {
      week: weekLabel,
      run_date: now.toISOString().split('T')[0],

      config: {
        mode: DEMO_MODE ? 'demo_test' : 'production',
        crm_mode: CRM_MODE,
        idle_days: IDLE_DAYS,
        stuck_days: STUCK_DAYS,
        uncontacted_days: UNCONTACTED_DAYS,
        production_recommendation: {
          idle_days: 14,
          stuck_days: 30,
          uncontacted_days: 7
  }
},

      summary: {
        total_open_deals: openDeals.length,
        total_pipeline_value: totalPipelineValue,
        weighted_pipeline: Math.round(weightedPipeline),
        monthly_target: MONTHLY_TARGET,
        forecast_gap: Math.round(forecastGap),
        at_risk_value: atRiskValue,
        at_risk_percentage: atRiskPercentage,
        pipeline_change_pct: pipelineChangePct,
        data_quality_score: dataQualityScore
      },

      critical: {
        idle_deals: {
          count: idleDeals.length,
          total_value: idleDeals.reduce((sum, d) => sum + d.amount, 0),
          items: idleDeals
        },
        overdue_deals: {
          count: overdueDeals.length,
          total_value: overdueDeals.reduce((sum, d) => sum + d.amount, 0),
          items: overdueDeals
        },
        uncontacted_leads: {
          count: uncontactedLeads.length,
          items: uncontactedLeads
        }
      },

      warnings: {
        stuck_deals: {
          count: stuckDeals.length,
          total_value: stuckDeals.reduce((sum, d) => sum + d.amount, 0),
          items: stuckDeals
        },
        missing_data: {
          contacts_no_reachable_info: missingData.contacts_no_reachable_info.length,
          deals_no_close_date: missingData.deals_no_close_date.length,
          deals_no_owner: missingData.deals_no_owner.length,
          items: missingData
        }
      },

      top_risk_deals: topRiskDeals,

      rep_performance: repScores,

      win_loss: {
        closed_won_count: closedWon.length,
        closed_lost_count: closedLost.length,
        won_value: wonValue,
        lost_value: lostValue,
        win_rate: winRate,
        closed_deal_count: closedDealCount
      },

      forecast: {
        weighted_pipeline: Math.round(weightedPipeline),
        monthly_target: MONTHLY_TARGET,
        gap: Math.round(forecastGap),
        on_track: forecastGap <= 0,
        confidence: forecastConfidence
      }
    }
  }
];

const data = $input.first().json;

const rows = [];

function addRow({
  record_type,
  record_name,
  owner = 'Unassigned',
  amount = 0,
  issue_type,
  severity,
  days = '',
  recommended_action,
  url = ''
}) {
  const cleanRecordName = String(record_name || 'unknown_record')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_');

  const cleanIssueType = String(issue_type || 'unknown_issue')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_');

  const issue_id = `${data.week}|${record_type}|${cleanRecordName}|${cleanIssueType}`;

  rows.push({
    json: {
      issue_id,
      week: data.week,
      run_date: data.run_date,
      record_type,
      record_name,
      owner,
      amount,
      issue_type,
      severity,
      days,
      recommended_action,
      url
    }
  });
}

// Idle deals
for (const deal of data.critical.idle_deals.items || []) {
  addRow({
    record_type: 'deal',
    record_name: deal.name,
    owner: deal.owner,
    amount: deal.amount,
    issue_type: 'idle_deal',
    severity: 'critical',
    days: deal.days_idle,
    recommended_action: 'Review deal and log next follow-up action in CRM',
    url: deal.url || ''
  });
}

// Overdue deals
for (const deal of data.critical.overdue_deals.items || []) {
  addRow({
    record_type: 'deal',
    record_name: deal.name,
    owner: deal.owner,
    amount: deal.amount,
    issue_type: 'overdue_close_date',
    severity: 'critical',
    days: deal.days_overdue,
    recommended_action: 'Update close date or move deal to closed won/lost',
    url: deal.url || ''
  });
}

// Leads with no logged follow-up
for (const lead of data.critical.uncontacted_leads.items || []) {
  addRow({
    record_type: 'contact',
    record_name: lead.name || 'Unnamed contact',
    owner: lead.owner,
    amount: 0,
    issue_type: 'no_logged_follow_up',
    severity: 'critical',
    days: lead.days_since_created,
    recommended_action: 'Assign owner and log first follow-up activity',
    url: lead.url || ''
  });
}

// Stuck deals
for (const deal of data.warnings.stuck_deals.items || []) {
  addRow({
    record_type: 'deal',
    record_name: deal.name,
    owner: deal.owner,
    amount: deal.amount,
    issue_type: 'stuck_deal',
    severity: 'warning',
    days: deal.days_in_stage,
    recommended_action: 'Review stage status and define next step',
    url: deal.url || ''
  });
}

// Contacts missing contact info
for (const contact of data.warnings.missing_data.items.contacts_no_reachable_info || []) {
  addRow({
    record_type: 'contact',
    record_name: contact.name || 'Unnamed contact',
    owner: contact.owner,
    amount: 0,
    issue_type: 'missing_contact_info',
    severity: 'warning',
    days: '',
    recommended_action: 'Add phone or email before next campaign',
    url: contact.url || ''
  });
}

// Deals missing close date
for (const deal of data.warnings.missing_data.items.deals_no_close_date || []) {
  addRow({
    record_type: 'deal',
    record_name: deal.name,
    owner: deal.owner,
    amount: deal.amount,
    issue_type: 'missing_close_date',
    severity: 'warning',
    days: '',
    recommended_action: 'Add expected close date for forecasting',
    url: deal.url || ''
  });
}

// Deals missing owner
for (const deal of data.warnings.missing_data.items.deals_no_owner || []) {
  addRow({
    record_type: 'deal',
    record_name: deal.name,
    owner: 'Unassigned',
    amount: deal.amount,
    issue_type: 'missing_owner',
    severity: 'critical',
    days: '',
    recommended_action: 'Assign a deal owner immediately',
    url: deal.url || ''
  });
}

// If no issues, log a clean run
if (rows.length === 0) {
  return [{
    json: {
      week: data.week,
      run_date: data.run_date,
      record_type: 'system',
      record_name: 'No issues detected',
      owner: '',
      amount: 0,
      issue_type: 'clean_run',
      severity: 'info',
      days: '',
      recommended_action: 'No action required',
      url: ''
    }
  }];
}

return rows;
